def fast_sort(arr):
    if len(arr) <= 1:
        return arr[:]
    # Heapsort - O(n log n) guaranteed, in-place
    result = arr[:]
    n = len(result)

    def sift_down(a, start, end):
        root = start
        while True:
            child = 2 * root + 1
            if child > end:
                break
            if child + 1 <= end and a[child] < a[child + 1]:
                child += 1
            if a[root] < a[child]:
                a[root], a[child] = a[child], a[root]
                root = child
            else:
                break

    # Build max heap
    for start in range((n - 2) // 2, -1, -1):
        sift_down(result, start, n - 1)

    # Extract elements
    for end in range(n - 1, 0, -1):
        result[0], result[end] = result[end], result[0]
        sift_down(result, 0, end - 1)

    return result

def fast_sort(arr):
    n = len(arr)
    if n <= 1:
        return arr[:]

    result = arr[:]

    def _insertion_sort(a, lo, hi):
        for i in range(lo + 1, hi + 1):
            key = a[i]
            j = i - 1
            while j >= lo and a[j] > key:
                a[j + 1] = a[j]
                j -= 1
            a[j + 1] = key

    def _sift_down(a, root, end):
        while True:
            child = 2 * root + 1
            if child > end:
                break
            if child + 1 <= end and a[child] < a[child + 1]:
                child += 1
            if a[root] < a[child]:
                a[root], a[child] = a[child], a[root]
                root = child
            else:
                break

    def _heapsort(a, lo, hi):
        n = hi - lo + 1
        for i in range((n - 2) // 2, -1, -1):
            _sift_down(a, lo + i, hi)
        for end in range(hi, lo, -1):
            a[lo], a[end] = a[end], a[lo]
            _sift_down(a, lo, end - 1)

    def _introsort(a, lo, hi, depth_limit):
        while hi - lo > 16:
            if depth_limit == 0:
                _heapsort(a, lo, hi)
                return
            depth_limit -= 1
            # Median of three
            mid = (lo + hi) // 2
            if a[lo] > a[mid]:
                a[lo], a[mid] = a[mid], a[lo]
            if a[lo] > a[hi]:
                a[lo], a[hi] = a[hi], a[lo]
            if a[mid] > a[hi]:
                a[mid], a[hi] = a[hi], a[mid]
            a[mid], a[hi - 1] = a[hi - 1], a[mid]
            pivot = a[hi - 1]
            i = lo
            j = hi - 1
            while True:
                i += 1
                while a[i] < pivot:
                    i += 1
                j -= 1
                while a[j] > pivot:
                    j -= 1
                if i >= j:
                    break
                a[i], a[j] = a[j], a[i]
            a[i], a[hi - 1] = a[hi - 1], a[i]
            # Recurse on smaller partition, iterate on larger
            if i - lo < hi - i:
                _introsort(a, lo, i - 1, depth_limit)
                lo = i + 1
            else:
                _introsort(a, i + 1, hi, depth_limit)
                hi = i - 1
        _insertion_sort(a, lo, hi)

    import math
    depth_limit = int(2 * math.log2(n))
    _introsort(result, 0, n - 1, depth_limit)
    return result

def fast_sort(arr):
    n = len(arr)
    if n <= 1:
        return arr[:]
    if n <= 48:
        result = arr[:]
        for i in range(1, n):
            key = result[i]
            j = i - 1
            while j >= 0 and result[j] > key:
                result[j + 1] = result[j]
                j -= 1
            result[j + 1] = key
        return result

    min_val = min(arr)
    max_val = max(arr)
    val_range = max_val - min_val

    if val_range == 0:
        return arr[:]

    if val_range < n * 3:
        counts = [0] * (val_range + 1)
        for x in arr:
            counts[x - min_val] += 1
        result = []
        append = result.append
        for i in range(val_range + 1):
            c = counts[i]
            if c == 1:
                append(i + min_val)
            elif c > 1:
                v = i + min_val
                for _ in range(c):
                    append(v)
        return result

    offset = -min_val if min_val < 0 else 0
    work = [x + offset for x in arr] if offset else arr[:]
    adjusted_max = max_val + offset
    buf = [0] * n
    mask = 0xFFFF

    # Pass 1 - precompute digits via list comprehension (runs in C frame)
    digits = [x & mask for x in work]
    count = [0] * 65537
    for d in digits:
        count[d + 1] += 1
    for i in range(1, 65537):
        count[i] += count[i - 1]
    for idx in range(n):
        d = digits[idx]
        buf[count[d]] = work[idx]
        count[d] += 1
    work, buf = buf, work

    if adjusted_max > mask:
        digits = [(x >> 16) & mask for x in work]
        count = [0] * 65537
        for d in digits:
            count[d + 1] += 1
        for i in range(1, 65537):
            count[i] += count[i - 1]
        for idx in range(n):
            d = digits[idx]
            buf[count[d]] = work[idx]
            count[d] += 1
        work, buf = buf, work

    if offset:
        return [x - offset for x in work]
    return work
